import{_ as o,H as d,f as t,i}from"./chunks/framework.DLd0CbzH.js";const S=JSON.parse('{"title":"UTS 开发必读与踩坑指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/uts-tips.md","filePath":"guide/uts-tips.md"}'),a={name:"guide/uts-tips.md"};function c(r,e,n,l,s,p){return d(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="uts-开发必读与踩坑指南" tabindex="-1">UTS 开发必读与踩坑指南 <a class="header-anchor" href="#uts-开发必读与踩坑指南" aria-label="Permalink to &quot;UTS 开发必读与踩坑指南&quot;">​</a></h1><p>在 <code>uni-app X</code> 的开发中，我们将使用 UTS (uni-app Type Script) 和 Vue 3 的组合。由于 UTS 最终会被编译为各平台的原生代码（如 Android 的 Kotlin、iOS 的 Swift），这就要求我们在编写代码时必须遵循更加严格的类型和语法规范。</p><div class="important custom-block github-alert"><p class="custom-block-title">核心法则</p><p><strong>安卓端语法最严</strong>：Android 编译器的 UTS 类型与语法校验是所有平台中最严格的。一般如果 Android 端编译正常通过，其他平台（H5、微信小程序、iOS等）通常都不会有大问题。</p></div><h2 id="_1-文件扩展名规范" tabindex="-1">1. 文件扩展名规范 <a class="header-anchor" href="#_1-文件扩展名规范" aria-label="Permalink to &quot;1. 文件扩展名规范&quot;">​</a></h2><p>在项目中，不要再使用传统的 <code>.vue</code> 和 <code>.ts</code>，请使用：</p><ul><li><strong><code>.uvue</code></strong>：用于编写页面（Pages）和组件（Components）。</li><li><strong><code>.uts</code></strong>：用于编写逻辑代码、Store、工具函数等。</li></ul><h2 id="_2-严格的类型系统" tabindex="-1">2. 严格的类型系统 <a class="header-anchor" href="#_2-严格的类型系统" aria-label="Permalink to &quot;2. 严格的类型系统&quot;">​</a></h2><p>UTS 具有比 TypeScript 更严格的类型校验机制：</p><ul><li><strong>不支持 <code>undefined</code></strong>：在 UTS 中，变量不能赋值为 <code>undefined</code>。</li><li><strong>联合类型的限制</strong>：目前 UTS 的联合类型仅支持与 <code>null</code> 联合（例如 <code>string | null</code>），不支持不同数据类型之间的联合（如 <code>string | number</code> 不合法，此时需考虑使用 <code>any</code> 或拆分）。</li><li><strong>判断相等</strong>：在 UTS 中，请使用 <code>==</code> 和 <code>!=</code> 进行比较，避免使用 <code>===</code> 和 <code>!==</code>，因为在编译到原生时，三等号可能会引起非预期的引用地址对比导致逻辑错误。</li></ul><h2 id="_3-css-样式限制" tabindex="-1">3. CSS 样式限制 <a class="header-anchor" href="#_3-css-样式限制" aria-label="Permalink to &quot;3. CSS 样式限制&quot;">​</a></h2><p>因为 <code>uni-app X</code> 的界面是由原生控件（如 <code>TextView</code>, <code>UIView</code> 等）直接渲染的，并不是 Web 浏览器环境，所以并不是所有 CSS 属性都能被支持：</p><ul><li><strong>不支持部分布局属性</strong>：原生平台不支持诸如 <code>display: grid</code> 等复杂的 Web 布局，请尽量使用 Flex 布局。</li><li><strong>Gap 属性</strong>：在部分旧版原生编译环境中对 <code>gap</code> 的支持有限，请优先考虑通过 <code>margin</code> 来控制元素间距。</li><li><strong>动态换肤</strong>：项目支持 SCSS 变量，但如果你需要实现运行时的动态主题覆盖，请配合 CSS 变量 (<code>var(--theme-color)</code>) 来实现。</li></ul><p>更多关于原生平台 CSS 支持范围的细节，请参阅 <a href="https://uniapp.dcloud.net.cn/uni-app-x/" target="_blank" rel="noreferrer">uni-app X 官方文档</a>。</p><h2 id="_4-api-环境限制" tabindex="-1">4. API 环境限制 <a class="header-anchor" href="#_4-api-环境限制" aria-label="Permalink to &quot;4. API 环境限制&quot;">​</a></h2><p><strong>不要使用任何浏览器特有的 API！</strong></p><p>由于原生 APP 平台（Android/iOS）中不存在浏览器环境，所以在 <code>.uts</code> 或 <code>.uvue</code> 代码中：</p><ul><li><code>window</code> 是不存在的。</li><li><code>document</code> 是不存在的（无法通过 DOM API 操作节点）。</li><li><code>localStorage</code> 和 <code>sessionStorage</code> 也是不存在的（请使用 uni 提供的 <code>uni.setStorageSync</code> 等持久化方案）。</li><li><code>navigator</code> 不存在。</li></ul><p>所有的平台差异或系统交互，都请依赖 <code>uni-app</code> 提供的跨端 API 或在 UTS 中直接调用原生 API 实现。</p>',18)])])}const g=o(a,[["render",c]]);export{S as __pageData,g as default};
